import{_ as d,o as r,c as a,a4 as e}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"第四章 中学生学习心理","description":"","frontmatter":{"title":"第四章 中学生学习心理","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"teacher-exam/education-knowledge/chapter4.md","filePath":"teacher-exam/education-knowledge/chapter4.md","lastUpdated":1783497010000}'),h={name:"teacher-exam/education-knowledge/chapter4.md"};function o(l,t,i,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="第四章-中学生学习心理" tabindex="-1">第四章 中学生学习心理 <a class="header-anchor" href="#第四章-中学生学习心理" aria-label="Permalink to &quot;第四章 中学生学习心理&quot;">​</a></h1><blockquote><p>本章考情：全题型覆盖，约 25-30 分，占分最高的章节 重点：学习理论、学习动机、学习迁移</p></blockquote><hr><h2 id="_4-1-认知过程-🔴🔴" tabindex="-1">4.1 认知过程 🔴🔴 <a class="header-anchor" href="#_4-1-认知过程-🔴🔴" aria-label="Permalink to &quot;4.1 认知过程 🔴🔴&quot;">​</a></h2><h3 id="感觉与知觉" tabindex="-1">感觉与知觉 <a class="header-anchor" href="#感觉与知觉" aria-label="Permalink to &quot;感觉与知觉&quot;">​</a></h3><p><strong>感觉适应</strong> 🔴：</p><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>举例</th></tr></thead><tbody><tr><td>暗适应</td><td>由亮到暗，感受性提高</td><td>进电影院适应黑暗</td></tr><tr><td>明适应</td><td>由暗到亮，感受性降低</td><td>从电影院出来被亮光晃眼</td></tr></tbody></table><p><strong>知觉特性</strong> 🔴🔴：</p><table tabindex="0"><thead><tr><th>特性</th><th>含义</th><th>举例</th></tr></thead><tbody><tr><td>选择性</td><td>把对象从背景中区分出来</td><td>万绿丛中一点红</td></tr><tr><td>整体性</td><td>把事物看成一个整体</td><td>只看部分也能认出整体</td></tr><tr><td>理解性</td><td>用已有经验理解知觉对象</td><td>内行看门道，外行看热闹</td></tr><tr><td>恒常性</td><td>知觉条件变化，映像不变</td><td>远处人虽小但知其身高不变</td></tr></tbody></table><h3 id="注意-🔴🔴" tabindex="-1">注意 🔴🔴 <a class="header-anchor" href="#注意-🔴🔴" aria-label="Permalink to &quot;注意 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>有无目的</th><th>是否需要意志</th><th>例</th></tr></thead><tbody><tr><td>无意注意</td><td>无</td><td>否</td><td>突然巨响、鲜艳颜色</td></tr><tr><td>有意注意</td><td>有</td><td>是</td><td>认真听课、专心解题</td></tr><tr><td>有意后注意 🔴</td><td>有</td><td>否（自动化）</td><td>熟练骑车、打字</td></tr></tbody></table><p><strong>注意的品质</strong> 🔴：</p><table tabindex="0"><thead><tr><th>品质</th><th>含义</th><th>影响因素</th></tr></thead><tbody><tr><td>注意的广度</td><td>同一时间能清楚把握的对象数量</td><td>对象排列、活动任务、个体经验</td></tr><tr><td>注意的稳定性</td><td>集中在某一对象上的持续时间</td><td>对象特点、个体状态</td></tr><tr><td>注意的分配</td><td>同时进行两种以上活动</td><td>活动熟练度、活动关系</td></tr><tr><td>注意的转移</td><td>主动从一个对象转到另一个</td><td>原注意的紧张度、新对象的吸引力</td></tr></tbody></table><h3 id="记忆-🔴🔴🔴" tabindex="-1">记忆 🔴🔴🔴 <a class="header-anchor" href="#记忆-🔴🔴🔴" aria-label="Permalink to &quot;记忆 🔴🔴🔴&quot;">​</a></h3><p><strong>记忆过程</strong>：识记→保持→再认/回忆</p><p><strong>艾宾浩斯遗忘曲线</strong> 🔴🔴🔴：</p><ul><li>遗忘规律：先快后慢，呈负加速型</li><li>启示：及时复习 🔴</li></ul><p><strong>遗忘原因</strong> 🔴：</p><table tabindex="0"><thead><tr><th>学说</th><th>核心观点</th></tr></thead><tbody><tr><td>衰退说</td><td>不用的记忆自动消退（感觉记忆、短时记忆）</td></tr><tr><td>干扰说 🔴</td><td>前后学习材料互相干扰</td></tr><tr><td>压抑说</td><td>情绪动机压抑（弗洛伊德）</td></tr><tr><td>提取失败说</td><td>存储但提取不出来（舌尖现象）</td></tr></tbody></table><p><strong>前摄抑制与倒摄抑制</strong> 🔴🔴：</p><ul><li>前摄抑制：前面学习的材料对后面学习的干扰</li><li>倒摄抑制：后面学习的材料对前面学习的干扰</li><li>早上学习只受倒摄抑制，晚上学习只受前摄抑制 → 早晚学习效果好</li></ul><p><strong>知识保持方法</strong> 🔴🔴：</p><ol><li>及时复习</li><li>分散复习优于集中复习</li><li>反复阅读与试图回忆相结合</li><li>多种感官参与</li><li>超额学习 150% 🔴</li></ol><h3 id="思维-🔴" tabindex="-1">思维 🔴 <a class="header-anchor" href="#思维-🔴" aria-label="Permalink to &quot;思维 🔴&quot;">​</a></h3><p><strong>思维特征</strong>：间接性、概括性</p><p><strong>思维种类</strong>：</p><table tabindex="0"><thead><tr><th>分类标准</th><th>类型</th></tr></thead><tbody><tr><td>发展水平</td><td>直觉动作思维→具体形象思维→抽象逻辑思维</td></tr><tr><td>指向性</td><td>聚合思维（求同）vs 发散思维（求异）</td></tr><tr><td>创新程度</td><td>常规思维 vs 创造性思维</td></tr></tbody></table><p><strong>创造性思维特征</strong> 🔴🔴：流畅性、变通性、独创性</p><hr><h2 id="_4-2-学习理论-🔴🔴🔴" tabindex="-1">4.2 学习理论 🔴🔴🔴 <a class="header-anchor" href="#_4-2-学习理论-🔴🔴🔴" aria-label="Permalink to &quot;4.2 学习理论 🔴🔴🔴&quot;">​</a></h2><blockquote><p>占分最高的知识点</p></blockquote><h3 id="行为主义-🔴🔴🔴" tabindex="-1">行为主义 🔴🔴🔴 <a class="header-anchor" href="#行为主义-🔴🔴🔴" aria-label="Permalink to &quot;行为主义 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>理论</th><th>人物</th><th>核心实验</th><th>关键概念</th></tr></thead><tbody><tr><td>经典条件作用</td><td>巴甫洛夫 🔴</td><td>狗唾液分泌</td><td>获得、消退、泛化、分化</td></tr><tr><td>试误说</td><td>桑代克</td><td>饿猫迷箱</td><td>三大定律：准备律、练习律、效果律 🔴</td></tr><tr><td>操作性条件作用</td><td>斯金纳 🔴🔴</td><td>白鼠按压杠杆</td><td>强化、惩罚、消退</td></tr><tr><td>社会学习理论</td><td>班杜拉 🔴</td><td>波波玩偶实验</td><td>观察学习、替代强化</td></tr></tbody></table><p><strong>斯金纳强化程式</strong> 🔴🔴🔴（必考）：</p><table tabindex="0"><thead><tr><th>概念</th><th>操作</th><th>行为变化</th><th>举例</th></tr></thead><tbody><tr><td>正强化</td><td>给予愉快刺激</td><td>行为增加 🔺</td><td>表现好→表扬</td></tr><tr><td>负强化 🔴</td><td>撤销厌恶刺激</td><td>行为增加 🔺</td><td>表现好→免作业</td></tr><tr><td>正惩罚</td><td>给予厌恶刺激</td><td>行为减少 🔻</td><td>犯错→罚站</td></tr><tr><td>负惩罚</td><td>撤销愉快刺激</td><td>行为减少 🔻</td><td>犯错→取消周末活动</td></tr><tr><td>消退</td><td>不给予任何强化</td><td>行为减少 🔻</td><td>哭闹→不理睬</td></tr></tbody></table><p><strong>辨析题高频</strong> 🔴🔴🔴：</p><ul><li>&quot;负强化就是惩罚&quot; → ❌ 负强化是撤销厌恶刺激使行为增加，惩罚是使行为减少</li><li>&quot;惩罚比强化更有效&quot; → ❌ 强化比惩罚更有效，惩罚只能抑制不能消除</li></ul><h3 id="认知主义-🔴🔴" tabindex="-1">认知主义 🔴🔴 <a class="header-anchor" href="#认知主义-🔴🔴" aria-label="Permalink to &quot;认知主义 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>理论</th><th>人物</th><th>核心观点</th><th>关键概念</th></tr></thead><tbody><tr><td>认知-发现说</td><td>布鲁纳 🔴</td><td>学习是主动形成认知结构</td><td>发现学习、认知结构、学科基本结构</td></tr><tr><td>认知-接受说</td><td>奥苏贝尔 🔴🔴</td><td>有意义接受学习</td><td>有意义学习、先行组织者 🔴</td></tr><tr><td>信息加工理论</td><td>加涅</td><td>学习是信息加工过程</td><td>八阶段学习过程</td></tr></tbody></table><p><strong>奥苏贝尔有意义学习</strong> 🔴🔴🔴：</p><p>条件：</p><ol><li>学习材料本身有逻辑意义</li><li>学习者认知结构中有适当观念</li><li>学习者有意义学习的心向</li></ol><p><strong>先行组织者</strong> 🔴🔴：先于学习任务本身呈现的引导性材料，比学习任务更抽象、概括</p><h3 id="建构主义-🔴🔴🔴" tabindex="-1">建构主义 🔴🔴🔴 <a class="header-anchor" href="#建构主义-🔴🔴🔴" aria-label="Permalink to &quot;建构主义 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>核心观点</th></tr></thead><tbody><tr><td>知识观</td><td>知识不是绝对真理，是解释和假设</td></tr><tr><td>学生观</td><td>学生不是空容器，有已有经验</td></tr><tr><td>学习观</td><td>主动建构、社会互动、情境性 🔴</td></tr><tr><td>教学观</td><td>创设情境、合作学习、支架式教学</td></tr></tbody></table><h3 id="人本主义-🔴" tabindex="-1">人本主义 🔴 <a class="header-anchor" href="#人本主义-🔴" aria-label="Permalink to &quot;人本主义 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>人物</th><th>核心主张</th></tr></thead><tbody><tr><td>马斯洛</td><td>需要层次理论，自我实现是最高需要</td></tr><tr><td>罗杰斯</td><td>以学生为中心，非指导性教学 🔴</td></tr></tbody></table><hr><h2 id="_4-3-学习动机-🔴🔴🔴" tabindex="-1">4.3 学习动机 🔴🔴🔴 <a class="header-anchor" href="#_4-3-学习动机-🔴🔴🔴" aria-label="Permalink to &quot;4.3 学习动机 🔴🔴🔴&quot;">​</a></h2><h3 id="学习动机分类-🔴" tabindex="-1">学习动机分类 🔴 <a class="header-anchor" href="#学习动机分类-🔴" aria-label="Permalink to &quot;学习动机分类 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分类标准</th><th>类型</th><th>举例</th></tr></thead><tbody><tr><td>动力来源</td><td>内部动机 🔴</td><td>对数学本身感兴趣</td></tr><tr><td></td><td>外部动机</td><td>为考试分数、家长奖励</td></tr><tr><td>社会意义</td><td>高尚动机</td><td>为中华崛起而读书</td></tr><tr><td></td><td>低级动机</td><td>为个人名利</td></tr><tr><td>作用时间</td><td>近景直接动机</td><td>为期末考试及格</td></tr><tr><td></td><td>远景间接动机</td><td>为将来当老师</td></tr></tbody></table><h3 id="学习动机理论-🔴🔴🔴" tabindex="-1">学习动机理论 🔴🔴🔴 <a class="header-anchor" href="#学习动机理论-🔴🔴🔴" aria-label="Permalink to &quot;学习动机理论 🔴🔴🔴&quot;">​</a></h3><h4 id="成就动机理论-阿特金森" tabindex="-1">成就动机理论（阿特金森） <a class="header-anchor" href="#成就动机理论-阿特金森" aria-label="Permalink to &quot;成就动机理论（阿特金森）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>倾向</th></tr></thead><tbody><tr><td>追求成功者</td><td>倾向选择中等难度任务 🔴</td><td>力争成功</td></tr><tr><td>避免失败者</td><td>倾向选择极难或极易任务 🔴</td><td>回避失败</td></tr></tbody></table><h4 id="韦纳归因理论-🔴🔴🔴-必考" tabindex="-1">韦纳归因理论 🔴🔴🔴（必考） <a class="header-anchor" href="#韦纳归因理论-🔴🔴🔴-必考" aria-label="Permalink to &quot;韦纳归因理论 🔴🔴🔴（必考）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>因素</th><th>控制点</th><th>稳定性</th><th>可控性</th></tr></thead><tbody><tr><td>能力</td><td>内部</td><td>稳定</td><td>不可控</td></tr><tr><td>努力 🔴🔴</td><td>内部</td><td>不稳定</td><td><strong>可控</strong></td></tr><tr><td>任务难度</td><td>外部</td><td>稳定</td><td>不可控</td></tr><tr><td>运气</td><td>外部</td><td>不稳定</td><td>不可控</td></tr><tr><td>身心状态</td><td>内部</td><td>不稳定</td><td>不可控</td></tr><tr><td>外界环境</td><td>外部</td><td>不稳定</td><td>不可控</td></tr></tbody></table><p><strong>教育启示</strong> 🔴🔴：引导学生归因于&quot;努力&quot;（唯一可控因素）</p><p><strong>辨析题</strong> 🔴：</p><ul><li>&quot;考试失败归因于能力不足会更有动力&quot; → ❌ 归因于能力（不可控）会降低动机</li><li>&quot;应引导学生归因于努力&quot; → ✅ 努力是唯一可控因素</li></ul><h4 id="自我效能感理论-班杜拉-🔴🔴" tabindex="-1">自我效能感理论（班杜拉）🔴🔴 <a class="header-anchor" href="#自我效能感理论-班杜拉-🔴🔴" aria-label="Permalink to &quot;自我效能感理论（班杜拉）🔴🔴&quot;">​</a></h4><p><strong>自我效能感</strong>：个体对自己能否成功完成某任务的主观判断</p><p><strong>影响因素</strong> 🔴：</p><ol><li>自身成败经验（最重要）🔴</li><li>替代经验</li><li>言语劝说</li><li>情绪唤醒</li></ol><h4 id="马斯洛需要层次理论-🔴🔴" tabindex="-1">马斯洛需要层次理论 🔴🔴 <a class="header-anchor" href="#马斯洛需要层次理论-🔴🔴" aria-label="Permalink to &quot;马斯洛需要层次理论 🔴🔴&quot;">​</a></h4><p>七个层次（由低到高）：生理→安全→归属与爱→尊重→认知→审美→自我实现 🔴</p><p><strong>教育启示</strong>：只有低层次需要满足后，高层次需要才能成为动力</p><h3 id="学习动机与学习效果-🔴" tabindex="-1">学习动机与学习效果 🔴 <a class="header-anchor" href="#学习动机与学习效果-🔴" aria-label="Permalink to &quot;学习动机与学习效果 🔴&quot;">​</a></h3><p><strong>耶克斯-多德森定律</strong> 🔴🔴：</p><ul><li>中等强度的动机最有利于任务完成</li><li>任务难度越高，最佳动机水平越低</li><li>任务难度越低，最佳动机水平越高</li></ul><hr><h2 id="_4-4-学习迁移-🔴🔴" tabindex="-1">4.4 学习迁移 🔴🔴 <a class="header-anchor" href="#_4-4-学习迁移-🔴🔴" aria-label="Permalink to &quot;4.4 学习迁移 🔴🔴&quot;">​</a></h2><h3 id="迁移分类-🔴" tabindex="-1">迁移分类 🔴 <a class="header-anchor" href="#迁移分类-🔴" aria-label="Permalink to &quot;迁移分类 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分类标准</th><th>类型</th><th>含义</th></tr></thead><tbody><tr><td>效果</td><td>正迁移 🔴</td><td>一种学习对另一种产生积极影响</td></tr><tr><td></td><td>负迁移</td><td>一种学习对另一种产生消极影响</td></tr><tr><td>方向</td><td>顺向迁移</td><td>先前学习影响后续学习</td></tr><tr><td></td><td>逆向迁移</td><td>后续学习影响先前学习</td></tr><tr><td>水平</td><td>水平迁移（横向）</td><td>并列关系间的迁移</td></tr><tr><td></td><td>垂直迁移（纵向）</td><td>上下位关系间的迁移</td></tr></tbody></table><h3 id="迁移理论-🔴" tabindex="-1">迁移理论 🔴 <a class="header-anchor" href="#迁移理论-🔴" aria-label="Permalink to &quot;迁移理论 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>理论</th><th>人物</th><th>核心观点</th></tr></thead><tbody><tr><td>形式训练说</td><td>—</td><td>迁移是心理官能的训练</td></tr><tr><td>相同要素说</td><td>桑代克</td><td>共同元素才能迁移</td></tr><tr><td>概括化理论</td><td>贾德 🔴</td><td>经验类化是迁移的关键</td></tr><tr><td>关系转换理论</td><td>苛勒</td><td>对关系的顿悟是迁移的关键</td></tr></tbody></table><h3 id="促进学习迁移的教学-🔴🔴" tabindex="-1">促进学习迁移的教学 🔴🔴 <a class="header-anchor" href="#促进学习迁移的教学-🔴🔴" aria-label="Permalink to &quot;促进学习迁移的教学 🔴🔴&quot;">​</a></h3><ol><li>精选教材</li><li>合理编排教学内容</li><li>合理安排教学程序</li><li>教授学习策略</li></ol><hr><h2 id="_4-5-学习策略-🔴" tabindex="-1">4.5 学习策略 🔴 <a class="header-anchor" href="#_4-5-学习策略-🔴" aria-label="Permalink to &quot;4.5 学习策略 🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>具体策略</th><th>举例</th></tr></thead><tbody><tr><td>认知策略</td><td>复述策略</td><td>划线、重复</td></tr><tr><td></td><td>精加工策略 🔴</td><td>做笔记、类比、口诀</td></tr><tr><td></td><td>组织策略</td><td>列提纲、画思维导图</td></tr><tr><td>元认知策略</td><td>计划策略</td><td>设定目标、浏览</td></tr><tr><td></td><td>监控策略</td><td>自我检查、集中注意</td></tr><tr><td></td><td>调节策略</td><td>调整阅读速度</td></tr><tr><td>资源管理策略</td><td>时间管理</td><td>制定计划</td></tr><tr><td></td><td>环境管理</td><td>选择安静场所</td></tr><tr><td></td><td>努力管理</td><td>自我激励</td></tr><tr><td></td><td>学业求助</td><td>请教老师同学</td></tr></tbody></table><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><h3 id="学习理论对比" tabindex="-1">学习理论对比 <a class="header-anchor" href="#学习理论对比" aria-label="Permalink to &quot;学习理论对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>流派</th><th>代表</th><th>核心词</th><th>一句话</th></tr></thead><tbody><tr><td>行为主义</td><td>斯金纳</td><td>刺激-反应</td><td>学习是行为的变化</td></tr><tr><td>认知主义</td><td>奥苏贝尔</td><td>认知结构</td><td>学习是认知的变化</td></tr><tr><td>建构主义</td><td>皮亚杰</td><td>主动建构</td><td>学习是主动建构意义</td></tr><tr><td>人本主义</td><td>罗杰斯</td><td>自我实现</td><td>学习是自我实现的过程</td></tr></tbody></table><h3 id="韦纳归因表速记" tabindex="-1">韦纳归因表速记 <a class="header-anchor" href="#韦纳归因表速记" aria-label="Permalink to &quot;韦纳归因表速记&quot;">​</a></h3><p><strong>能力</strong>=内部+稳定+不可控；<strong>努力</strong>🔴=内部+不稳定+<strong>可控</strong>；<strong>任务</strong>=外部+稳定+不可控；<strong>运气</strong>=外部+不稳定+不可控</p><h3 id="辨析题必背" tabindex="-1">辨析题必背 <a class="header-anchor" href="#辨析题必背" aria-label="Permalink to &quot;辨析题必背&quot;">​</a></h3><table tabindex="0"><thead><tr><th>说法</th><th>判断</th></tr></thead><tbody><tr><td>负强化=惩罚</td><td>❌ 负强化增行为，惩罚减行为</td></tr><tr><td>知识=能力</td><td>❌ 需要转化</td></tr><tr><td>迁移都是正面的</td><td>❌ 还有负迁移</td></tr></tbody></table>',88)])])}const q=d(h,[["render",o]]);export{c as __pageData,q as default};
